// get user name
function getUserName(user) {
    return user;
}

// increment counter value
function incrementCounterValue(counter, value) {
    return counter + value;
}

// validate input data
function validateInputData(input, data) {
    return input.length > 0 && data.length > 0;
}

// calculate total price
function calculateTotalPrice(total, price) {
    return total + price;
}
